--
-- Table structure for table `restaurants`
--

DROP TABLE IF EXISTS `restaurants`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `restaurants` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(200) NOT NULL,
  `cuisine_type` varchar(100) DEFAULT NULL,
  `description` text,
  `address` varchar(500) DEFAULT NULL,
  `city` varchar(100) DEFAULT NULL,
  `state` varchar(10) DEFAULT NULL,
  `zip_code` varchar(20) DEFAULT NULL,
  `phone` varchar(20) DEFAULT NULL,
  `email` varchar(255) DEFAULT NULL,
  `website` varchar(500) DEFAULT NULL,
  `hours_of_operation` text,
  `pricing_tier` varchar(10) DEFAULT NULL,
  `amenities` text,
  `ambiance` varchar(100) DEFAULT NULL,
  `average_rating` float DEFAULT NULL,
  `review_count` int DEFAULT NULL,
  `owner_id` int DEFAULT NULL,
  `created_by` int NOT NULL,
  `created_at` datetime DEFAULT (now()),
  `updated_at` datetime DEFAULT NULL,
  `status` enum('pending','approved','rejected') DEFAULT 'approved',
  PRIMARY KEY (`id`),
  KEY `owner_id` (`owner_id`),
  KEY `created_by` (`created_by`),
  KEY `ix_restaurants_name` (`name`),
  KEY `ix_restaurants_city` (`city`),
  KEY `ix_restaurants_id` (`id`),
  CONSTRAINT `restaurants_ibfk_1` FOREIGN KEY (`owner_id`) REFERENCES `users` (`id`),
  CONSTRAINT `restaurants_ibfk_2` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=500 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `restaurants`
--

LOCK TABLES `restaurants` WRITE;
/*!40000 ALTER TABLE `restaurants` DISABLE KEYS */;
INSERT INTO `restaurants` VALUES (1,'Denny\'s','American','Indulge in classic comfort food at Denny\'s, a San Francisco staple serving up fluffy pancakes, crispy bacon, and warm smiles since 1953 - a quintessential Bay Area breakfast spot that\'s equal parts retro charm and modern delight!','Various Locations','San Francisco',NULL,NULL,'N/A',NULL,NULL,NULL,'3',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(2,'Mountain Mike\'s','Pizza','Get ready for a taste of California cool at Mountain Mike\'s, where San Francisco\'s best pizza meets the laid-back vibes of the Bay Area. Savor their famous pepperoni pies, made with fresh ingredients and cooked to perfection in a brick oven that\'ll transport you to the rolling hills of Napa Valley. In the heart of SF, this mountain-inspired spot serves up pies that are as iconic as the Golden Gate Bridge!','2042','San Francisco',NULL,NULL,'N/A',NULL,NULL,NULL,'4',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(3,'Rama V Thai Cuisine','Thai','Indulge in the bold flavors of Thailand at Rama V, where spicy curries and fragrant street food come together in a vibrant celebration of San Francisco\'s diverse culinary scene. Savor the rich aromas of lemongrass and galangal wafting from the kitchen, transporting you to the bustling streets of Bangkok. In the heart of SF, Rama V serves up authentic Thai comfort with a Bay Area twist.','1028 East El Camino Real','San Francisco',NULL,NULL,'+1-408-738-2177',NULL,NULL,NULL,'3',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(4,'Komala Vilas','Indian','Indulge in the rich flavors of India at Komala Vilas, a San Francisco institution serving up authentic, mouth-watering dishes that transport you to the bustling streets of Mumbai. Savor tender curries, fluffy basmati rice, and crispy naan bread in this cozy Bay Area gem, where every bite is a taste of home.','Various Locations','San Francisco',NULL,NULL,'N/A',NULL,NULL,NULL,'4',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(5,'bb.q Chicken','Chicken','Get ready for a flavor explosion in the heart of Silicon Valley! At bb.q Chicken, expertly marinated and grilled to perfection, their juicy chicken is served with a side of steamed bok choy and pickled ginger, all at an unbeatable price. A Bay Area favorite that\'s quick, delicious, and totally worth the trip!','561 East El Camino Real','Sunnyvale',NULL,NULL,'+1 408 743 5787',NULL,NULL,NULL,'1',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(6,'Pizz’a Chicago','Pizza','Get a taste of the Windy City in the heart of Silicon Valley at Pizz\'a Chicago, where classic Chicago-style deep dish pizza meets Bay Area vibes. Savor our signature thick-crusted pies loaded with melted mozzarella, tangy tomato sauce, and savory meats, all made fresh daily in Santa Clara.','1576 Halford Avenue','Santa Clara',NULL,NULL,'N/A',NULL,NULL,NULL,'3',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(7,'Ginger Cafe','Chinese','Get your kung pao fix in the City by the Bay at Ginger Cafe, where San Francisco\'s vibrant energy meets authentic Chinese flavors. Born and raised locals will feel right at home with dishes like Kung Pao chicken and mapo tofu, while newcomers can discover the rich culinary heritage of this iconic neighborhood. Come taste the spirit of SF\'s eclectic music scene - just like The Grateful Dead, your taste buds will be forever changed!','Various Locations','San Francisco',NULL,NULL,'N/A',NULL,NULL,NULL,'3',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(8,'Il Fornaio','Italian','Indulge in authentic Italian flavors at Il Fornaio, San Francisco\'s premier destination for upscale dining. Savor traditional Tuscan dishes crafted with fresh ingredients and a touch of Italian flair, all in the heart of the Bay Area. From wood-fired pizzas to homemade pastas, every bite transports you to the rolling hills of Italy.','Various Locations','San Francisco',NULL,NULL,'N/A',NULL,NULL,NULL,'4',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(9,'Barracuda','Japanese','Dive into the bold flavors of Japan at Barracuda in Burlingame, where every bite is a high-stakes mission for your taste buds. Savor our signature sushi rolls and hot pots, expertly crafted to leave you shaken, not stirred - just like Bond himself. In this San Francisco Bay Area hotspot, the thrill of discovery meets the art of Japanese cuisine.','347 Primrose Road','Burlingame',NULL,NULL,'+1 650-548-0300',NULL,NULL,NULL,'1',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(10,'Swati Tiffins','American','Indulge in modern American comfort food with an international twist at Swati Tiffins in San Francisco, where flavors from across the globe meet California\'s fresh vibes. Inspired by the vibrant streets of Bengaluru, this restaurant serves up creative twists on classic dishes that will transport you to the heart of India. Come for the bold flavors, stay for the cozy atmosphere!','Various Locations','San Francisco',NULL,NULL,'N/A',NULL,NULL,NULL,'4',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(11,'Tomatina','American','Tomatina brings a breezy California-Italian dining experience that blends casual comfort with bold, satisfying flavors. Known for its hand-tossed pizzas, house-made pastas, and signature garlic rolls that arrive warm and irresistible, the restaurant has built a loyal following across the Bay Area. The atmosphere is relaxed and family-friendly, making it a perfect spot for everything from weekday lunches to easygoing dinners with friends where generous portions and familiar flavors always deliver.','3127','San Francisco',NULL,NULL,'+1-408-654-9000',NULL,NULL,NULL,'3',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(12,'Tostadas Prime','Mexican','Tostadas Prime offers a lively and modern take on Mexican cuisine, with a strong emphasis on seafood-forward dishes and vibrant presentation. The menu features beautifully layered tostadas, rich ceviches, and bold cocktails that pair perfectly with the upbeat ambiance. With music, stylish decor, and a festive energy that fills the space, it feels more like a celebration than a standard meal, making it a favorite for gatherings, date nights, and anyone craving elevated Mexican flavors.','3149 Mission College Boulevard','Santa Clara',NULL,NULL,'N/A',NULL,NULL,NULL,'3',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(13,'Terrace Cafe','American','Terrace Cafe provides a polished yet approachable American dining experience centered around fresh ingredients and comforting favorites. Guests can expect a menu filled with crisp salads, hearty sandwiches, and satisfying entrees alongside indulgent desserts that round out the meal. The cozy interior and relaxed atmosphere make it equally suited for a quick lunch break or a leisurely dinner, offering a dependable neighborhood feel with just enough refinement to keep things interesting.','Various Locations','San Francisco',NULL,NULL,'N/A',NULL,NULL,NULL,'1',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(14,'Celia\'s','Mexican','Celia\'s stands as a long-running San Francisco institution, bringing decades of tradition to its classic Mexican menu and welcoming cantina-style setting. Known for its strong margaritas, generous plates of enchiladas, and comforting combination platters, the restaurant delivers a nostalgic experience that keeps generations of diners returning. Its warm, family-oriented atmosphere and consistent flavors make it a cornerstone of the local dining scene and a reliable go-to for authentic comfort.','Various Locations','San Francisco',NULL,NULL,'N/A',NULL,NULL,NULL,'3',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(15,'Fish Market Restaurant','Seafood','Fish Market Restaurant captures the timeless appeal of a classic seafood house, focusing on fresh ingredients and straightforward preparations that let the quality of the catch shine. Diners can enjoy oysters, grilled fish, and hearty chowders in a relaxed, maritime-inspired setting that evokes coastal charm. Whether you are stopping in for a casual lunch or a full seafood feast, the menu offers something for every seafood lover seeking clean, bold flavors.','Various Locations','San Francisco',NULL,NULL,'N/A',NULL,NULL,NULL,'3',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(16,'Broadway Grill Inc','American','Broadway Grill offers a refined yet welcoming take on American grill cuisine, serving up steaks, seafood, and hearty classics in a charming historic setting. The ambiance strikes a balance between upscale and comfortable, making it ideal for both special occasions and relaxed dinners. With attentive service and thoughtfully prepared dishes, it delivers a polished dining experience that still feels approachable and satisfying.','Various Locations','San Francisco',NULL,NULL,'N/A',NULL,NULL,NULL,'1',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(17,'Treehouse','Mexican','Treehouse blends casual dining with bold Mexican-inspired flavors, creating a relaxed and lively environment that appeals to students and locals alike. The menu features everything from tacos and burritos to comfort food favorites, making it versatile and approachable. With its laid-back vibe and satisfying portions, it is a dependable spot for quick meals, casual hangouts, and late-night cravings that call for something flavorful and filling.','Various Locations','San Francisco',NULL,NULL,'N/A',NULL,NULL,NULL,'3',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(18,'Fish & Bird Sousaku Izakaya','Japanese','Fish & Bird Sousaku Izakaya offers a modern and elevated interpretation of the traditional Japanese izakaya experience, focusing on small plates designed for sharing. The menu highlights expertly crafted sushi, seasonal ingredients, and creative dishes that showcase both technique and flavor. Paired with a sleek, intimate setting and a strong sake selection, it creates a dining experience that feels refined yet welcoming for both special occasions and relaxed evenings.','2451 Shattuck Avenue','Berkeley',NULL,NULL,'+1-510-705-1539',NULL,NULL,NULL,'4',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(19,'Mel\'s Drive-in','Diner','Mel\'s Drive-In is a beloved San Francisco classic that brings retro diner culture to life with its nostalgic decor, jukebox vibes, and hearty American comfort food. Known for its burgers, fries, and thick milkshakes, it delivers a fun, throwback experience that appeals to both locals and visitors. The lively atmosphere and generous portions make it a great choice for families, late-night diners, or anyone craving timeless diner favorites.','Various Locations','San Francisco',NULL,NULL,'+1-415-921-2867',NULL,NULL,NULL,'1',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(20,'Ray\'s Grill','American','Ray\'s Grill near Stanford offers a casual and versatile dining experience with a menu that spans burgers, burritos, sandwiches, and comfort food staples. Popular among students and locals, the restaurant features a relaxed outdoor seating area that encourages lingering meals and social gatherings. Its approachable pricing, generous portions, and laid-back vibe make it a go-to spot for quick bites or extended hangouts.','750 Escondido Road','Stanford',NULL,NULL,'N/A',NULL,NULL,NULL,'2',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(21,'Mezze and Mooore','Lebanese','Mezze and Mooore introduces the rich flavors of Lebanese cuisine through a menu filled with vibrant mezze, grilled meats, and house-made specialties. The dishes emphasize fresh herbs, bold spices, and traditional techniques that create a deeply satisfying dining experience. With its welcoming atmosphere and shareable plates, it is an ideal place for group dining where conversation and flavor come together effortlessly.','198 Guerrero Street','San Francisco',NULL,NULL,'+1 415 6545089',NULL,NULL,NULL,'3',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(22,'Rara','Nepalese','Rara brings authentic Nepalese cuisine to Palo Alto, offering a unique culinary experience inspired by Himalayan traditions. The menu features favorites like momo dumplings, flavorful curries, and aromatic rice dishes that reflect the depth of Nepalese cooking. The warm, inviting setting enhances the experience, making it a standout destination for diners seeking something different and culturally rich.','201 South California Avenue','Palo Alto',NULL,NULL,'+1 650 485 1055',NULL,NULL,NULL,'3',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(23,'Homma’s Brown Rice Sushi','Sushi','Homma\'s Brown Rice Sushi is a beloved hidden gem known for its distinctive use of brown rice, which adds a nutty depth to traditional sushi offerings. The small, intimate space emphasizes quality and attention to detail, with fresh fish and carefully prepared rolls that stand out from typical sushi spots. It is a must-visit for those looking to experience sushi with a unique and health-conscious twist.','Various Locations','San Francisco',NULL,NULL,'N/A',NULL,NULL,NULL,'2',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(24,'Palo Alto Sol','Mexican','Palo Alto Sol delivers classic Mexican cuisine in a cozy and inviting setting that feels like a neighborhood staple. The menu features a wide range of dishes, from sizzling fajitas to fresh ceviche, all prepared with bold flavors and generous portions. Its friendly service and relaxed ambiance make it a dependable choice for casual meals and gatherings.','408 South California Avenue','Palo Alto',NULL,NULL,'+1-650-328-8840',NULL,NULL,NULL,'1',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(25,'Ramen Kowa','Japanese','Ramen Kowa specializes in authentic ramen crafted with rich broths, perfectly cooked noodles, and carefully balanced toppings. The menu includes a variety of styles, from tonkotsu to spicy miso, each delivering depth and comfort in every bowl. With its modern yet cozy interior, it offers an inviting space to enjoy a satisfying and flavorful meal.','445 South California Avenue','Palo Alto',NULL,NULL,'+1 650-326-8640',NULL,NULL,NULL,'2',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(26,'Cafe Pro Bono','American','Cafe Pro Bono has built a strong reputation for its approachable Italian-American cuisine, featuring fresh pasta, flavorful sauces, and hearty entrees. The welcoming atmosphere and attentive service make it suitable for both casual dinners and special occasions. Its consistent quality and comforting dishes have earned it a loyal following in the area.','2439 Birch Street','San Francisco',NULL,NULL,'N/A',NULL,NULL,NULL,'1',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(27,'Sekoya','American','Sekoya offers a modern American dining experience with a focus on seasonal ingredients and refined presentation. The stylish interior and thoughtfully curated menu create an upscale yet approachable environment. It is a great choice for business meals, date nights, or anyone seeking a polished dining experience.','417 South California Avenue','Palo Alto',NULL,NULL,'N/A',NULL,NULL,NULL,'2',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(28,'Zareen\'s','Pakistani','Zareen\'s is widely celebrated for its Pakistani and Indian cuisine, delivering bold, authentic flavors in a lively and welcoming setting. Signature dishes like samosas, kebabs, and thalis showcase a depth of spice and tradition. The restaurant has become a local favorite for its consistency, quality, and vibrant culinary identity.','365 South California Avenue','Palo Alto',NULL,NULL,'+1 650-562-8700',NULL,NULL,NULL,'4',NULL,NULL,NULL,NULL,NULL,1,'2026-03-20 01:45:45',NULL,'approved'),(29,'Homemade Cafe','Brunch','Homema